  SymbolDatabase,
  SourceLocation,
} from "./database"

export function findDefinition(
  db: SymbolDatabase,
  symbol: string
): SourceLocation | null {
  const entry = db.get(symbol)
  if (!entry) return null
  if (entry.definition.file === "" && entry.definition.line === 0) return null
  return entry.definition
}

export function findReferences(
  db: SymbolDatabase,
  symbol: string
): SourceLocation[] {
  const entry = db.get(symbol)
  if (!entry) return []
  return [...entry.references]
}

export function findCallers(
  db: SymbolDatabase,
  func: string
): SourceLocation[] {
  const entry = db.get(func)
  if (!entry) return []
  const funcDef = entry.definition
  if (funcDef.file === "" && funcDef.line === 0) return []

  const callSites = entry.references.filter((ref) => {
    if (ref.file === funcDef.file && ref.line === funcDef.line) return false
    return true
  })

  const callerDefs = new Set<string>()
  const result: SourceLocation[] = []

  for (const site of callSites) {
    const key = `${site.file}:${site.line}`
    if (callerDefs.has(key)) continue
    callerDefs.add(key)
    result.push(site)
  }

  return result
}
